    // ── RELOAD ONLY THE RIGHT PANEL via AJAX ─────────────────────────────
    function reloadPanel() {
        fetch('/IPDBilling/GetBillPanel?ipdId=' + ipdId)
        .then(function(r) { return r.text(); })
        .then(function(html) {
            document.getElementById('billPanelContainer').innerHTML = html;
            fetch('/IPDBilling/GetBillBanner?ipdId=' + ipdId)
            .then(function(r) { return r.text(); })
            .then(function(bannerHtml) {
                document.getElementById('billBannerContainer').innerHTML = bannerHtml;
            });
            recalculate();
        })
        .catch(function() {
            toastr.error('Failed to refresh panel.');
        });
    }

    function recalculate() {
        // BED — editable input boxes
        var bed = 0;
        document.querySelectorAll('.bed-");
            WriteLiteral(@"charge').forEach(function(el) {
            bed += parseFloat(el.value) || 0;
        });

        // DOCTOR
        var doc = 0;
        document.querySelectorAll('.doctor-charge').forEach(function(el) {
            doc += parseFloat(el.value) || 0;
        });

        // MEDICINES
        var med = 0;
        document.querySelectorAll('.med-price').forEach(function(el) {
            var row  = el.closest('tr');
            var aqEl = row.querySelector('.med-actualqty');
            var qty  = parseFloat(aqEl ? aqEl.value : 1) || 0;
            var price = parseFloat(el.value) || 0;
            var total = price * qty;
            med += total;
            var totEl = row.querySelector('.med-total');
            if (totEl) totEl.innerText = '₹' + total.toFixed(2);
        });

        // INVESTIGATIONS
        var inv = 0;
        document.querySelectorAll('.inv-charge').forEach(function(el) {
            inv += parseFloat(el.value) || 0;
        });

        // DISCHARGE MEDICI");
            WriteLiteral(@"NES
        var dmed = 0;
        document.querySelectorAll('.dmed-price').forEach(function(el) {
            var days  = parseInt(el.dataset.days) || 1;
            var price = parseFloat(el.value) || 0;
            var total = price * days;
            dmed += total;
            var row = el.closest('tr');
            if (row) {
                var totEl = row.querySelector('.dmed-total');
                if (totEl) totEl.innerText = '₹' + total.toFixed(2);
            }
        });

        // NURSING — editable input boxes
        var nurse = 0;
        document.querySelectorAll('.nurse-charge').forEach(function(el) {
            nurse += parseFloat(el.value) || 0;
