            'totalMedLbl':   '₹ ' + med.toFixed(2),
            'totalInvLbl':   '₹ ' + inv.toFixed(2),
            'totalNurseLbl': '₹ ' + nurse.toFixed(2),
            'totalOpLbl':    '₹ ' + op.toFixed(2),
