            'sumSubTotal':   '₹' + subTotal.toFixed(2),
            'sumDiscount':   '-₹' + discAmt.toFixed(2),
            'sumTotal':      '₹' + total.toFixed(2)
        };
        Object.keys(elMap).forEach(function(id) {
