    function addOtherCharge() {
        var masterSel  = document.getElementById('ddlBillingMaster');
        var customName = document.getElementById('txtOtherName').value.trim();
        var qty  = parseInt(document.getElementById('txtOtherQty').value) || 1;
        var amt  = parseFloat(document.getElementById('txtOtherAmt').value) || 0;
        var name = '', masterId = null;

        if (masterSel.value) {
            masterId ");
            WriteLiteral(@"= masterSel.value;
            name = masterSel.options[masterSel.selectedIndex].text.split(' - ')[0];
            if (!amt) amt = parseFloat(
                masterSel.options[masterSel.selectedIndex].text.split('₹')[1]) || 0;
        } else if (customName) {
            name = customName;
        } else {
            alert('Select from list or enter custom name');
            return;
        }
        if (amt <= 0) { alert('Enter amount'); return; }

        var total = qty * amt;
        otherCounter++;
        otherItems.push({ id: otherCounter, masterId, name, qty, unit: amt, total });

        var noRow = document.getElementById('noOtherRow');
        if (noRow) noRow.remove();

        document.getElementById('otherChargesBody').insertAdjacentHTML('beforeend', `
            <tr id=""otherRow_${otherCounter}"">
                <td>${otherCounter}</td><td>${name}</td><td>${qty}</td>
                <td>₹${amt.toFixed(2)}</td><td>₹${total.toFixed(2)}</td>
                <td><button t");
            WriteLiteral(@"ype=""button"" class=""btn btn-sm btn-danger""
                    onclick=""removeOtherCharge(${otherCounter})"">✕</button></td>
            </tr>`);

        masterSel.value = '';
        document.getElementById('txtOtherName').value = '';
        document.getElementById('txtOtherQty').value  = '1';
        document.getElementById('txtOtherAmt').value  = '0';
        recalculate();
    }

    function removeOtherCharge(id) {
        otherItems = otherItems.filter(function(x) { return x.id !== id; });
        document.getElementById('otherRow_' + id)?.remove();
        recalculate();
    }

    function saveBill() {
        // Read all values from editable input boxes
        var bed = 0;
        document.querySelectorAll('.bed-charge').forEach(function(el) { bed += parseFloat(el.value) || 0; });
        var doc = 0;
        document.querySelectorAll('.doctor-charge').forEach(function(el) { doc += parseFloat(el.value) || 0; });
        var med = 0;
        document.querySelectorAll('.med-pr");
            WriteLiteral(@"ice').forEach(function(el) {
            var row = el.closest('tr');
            var aqEl = row.querySelector('.med-actualqty');
            var qty = parseFloat(aqEl ? aqEl.value : 1) || 0;
            med += (parseFloat(el.value) || 0) * qty;
        });
        var inv = 0;
        document.querySelectorAll('.inv-charge').forEach(function(el) { inv += parseFloat(el.value) || 0; });
        var dmed = 0;
        document.querySelectorAll('.dmed-price').forEach(function(el) {
            var days = parseInt(el.dataset.days) || 1;
            dmed += (parseFloat(el.value) || 0) * days;
        });
        var nurse = 0;
        document.querySelectorAll('.nurse-charge').forEach(function(el) { nurse += parseFloat(el.value) || 0; });
        var op = 0;
        document.querySelectorAll('.op-charge').forEach(function(el) { op += parseFloat(el.value) || 0; });
        var other = 0;
        otherItems.forEach(function(x) { other += x.total; });

        var subTotal = bed + doc + med + inv + ");
            WriteLiteral(@"dmed + nurse + op + other;
        var discPctEl = document.getElementById('txtDiscountPct');
        var discPct = discPctEl ? (parseFloat(discPctEl.value) || 0) : 0;
        var discAmt = subTotal * discPct / 100;
        var total = subTotal - discAmt;

        var items = otherItems.map(function(x) {
            return {
                itemType: 'Other',
                billingMasterId: x.masterId ? parseInt(x.masterId) : null,
                itemName: x.name, quantity: x.qty,
                unitPrice: x.unit, totalPrice: x.total
            };
        });

        var btn = document.querySelector('button[onclick=""saveBill()""]');
        if (btn) btn.disabled = true;

        fetch('/IPDBilling/SaveBill', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                ipdId: ipdId,
                bedCharges: bed, doctorCharges: doc,
                medicineCharges: med, investigationCharges: inv,
   ");
            WriteLiteral(@"             dischargeCharges: dmed, nursingCharges: nurse,
                operationCharges: op, otherCharges: other,
                subTotal: subTotal, discountPercent: discPct,
                discountAmount: discAmt, totalAmount: total,
                items: items
            })
        })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            if (data.success) {
                toastr.success('Bill generated successfully!');
                reloadPanel();
            } else {
                toastr.error('Error: ' + data.message);
                if (btn) btn.disabled = false;
            }
        })
        .catch(function(err) {
            toastr.error('Error: ' + err);
            if (btn) btn.disabled = false;
        });
    }

